"use client";

import { useAuth } from "@/lib/auth-context";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Users, BookOpen, AlertCircle, FileText } from "lucide-react";

export default function CoordinatorDashboard() {
    const { userProfile } = useAuth();

    const stats = [
        { title: "Total Students", value: "1,245", trend: "+12", trendUp: true, icon: Users, color: "text-blue-400", bg: "bg-blue-500/10" },
        { title: "Active Faculty", value: "84", trend: "+2", trendUp: true, icon: BookOpen, color: "text-purple-400", bg: "bg-purple-500/10" },
        { title: "Upcoming Exams", value: "6", trend: "Next Week", trendUp: true, icon: FileText, color: "text-amber-400", bg: "bg-amber-500/10" },
        { title: "Pending Requests", value: "15", trend: "Urgent", trendUp: false, icon: AlertCircle, color: "text-red-400", bg: "bg-red-500/10" },
    ];

    return (
        <DashboardLayout role="coordinator" title="Overview">
            {/* Greeting */}
            <div className="mb-8 fade-in">
                <h1 className="text-3xl font-bold text-white mb-2">Welcome, {userProfile?.name?.split(" ")[0]}! 👋</h1>
                <p className="text-slate-400">Here's the institution overview for today.</p>
            </div>

            {/* Quick Stats */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
                {stats.map((stat, i) => (
                    <div key={i} className="stat-card fade-in" style={{ animationDelay: `${i * 100}ms` }}>
                        <div className="flex items-center justify-between mb-4">
                            <div className={`p-3 rounded-xl ${stat.bg}`}>
                                <stat.icon className={`w-6 h-6 ${stat.color}`} />
                            </div>
                            <span className={`text-xs font-semibold px-2 py-1 rounded-full ${stat.trendUp ? "bg-emerald-500/10 text-emerald-400" : "bg-red-500/10 text-red-400"
                                }`}>
                                {stat.trend}
                            </span>
                        </div>
                        <p className="text-2xl font-bold text-white mb-1">{stat.value}</p>
                        <p className="text-sm font-medium text-slate-400">{stat.title}</p>
                    </div>
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Recent Activities */}
                <div className="glass-card p-6 fade-in" style={{ animationDelay: "400ms" }}>
                    <div className="flex items-center justify-between mb-6">
                        <h2 className="text-lg font-bold text-white">Recent Activities</h2>
                        <button className="text-emerald-400 text-sm hover:underline">View All</button>
                    </div>
                    <div className="space-y-4">
                        {[
                            { title: "Exam Schedule Published", time: "2 hours ago", type: "exam" },
                            { title: "New Faculty Onboarded: Dr. Smith", time: "5 hours ago", type: "faculty" },
                            { title: "System Maintenance Completed", time: "1 day ago", type: "system" },
                        ].map((activity, i) => (
                            <div key={i} className="flex gap-4 p-3 rounded-xl hover:bg-white/5 transition-colors">
                                <div className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center flex-shrink-0 text-slate-300">
                                    {activity.type === 'exam' ? '📝' : activity.type === 'faculty' ? '👥' : '⚙️'}
                                </div>
                                <div>
                                    <p className="text-sm font-medium text-white">{activity.title}</p>
                                    <p className="text-xs text-slate-400 mt-1">{activity.time}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Quick Actions */}
                <div className="glass-card p-6 fade-in" style={{ animationDelay: "500ms" }}>
                    <h2 className="text-lg font-bold text-white mb-6">Quick Actions</h2>
                    <div className="grid grid-cols-2 gap-4">
                        {[
                            { name: "Manage Users", dest: "/coordinator/users" },
                            { name: "Publish Notice", dest: "/coordinator/notices" },
                            { name: "Approve Leaves", dest: "/coordinator/leaves" },
                            { name: "System Settings", dest: "/coordinator/settings" },
                        ].map((action, i) => (
                            <button key={i} className="p-4 rounded-xl bg-gradient-to-br from-slate-800 to-slate-900 border border-white/5 hover:border-emerald-500/30 transition-all text-left group">
                                <p className="text-sm font-medium text-white group-hover:text-emerald-400 transition-colors">{action.name}</p>
                            </button>
                        ))}
                    </div>
                </div>
            </div>
        </DashboardLayout>
    );
}

"use client";

import { useState } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_LEAVES } from "@/lib/demo-data";
import { CalendarClock, CheckCircle, Search } from "lucide-react";
import { formatDate } from "@/lib/utils";

export default function CoordinatorLeavesPage() {
    const [requests, setRequests] = useState(DEMO_LEAVES.filter(l => l.status === "pending"));
    const [search, setSearch] = useState("");

    const handleAction = (id: string, action: "approved" | "rejected") => {
        setRequests(prev => prev.filter(r => r.id !== id));
        // In a real application, update Firebase and perhaps send an email notification.
    };

    const filtered = requests.filter(r =>
        r.applicant.toLowerCase().includes(search.toLowerCase()) ||
        r.reason.toLowerCase().includes(search.toLowerCase())
    );

    return (
        <DashboardLayout role="coordinator" title="Master Leave Approvals">
            <div className="page-header">Campus Leave Approvals</div>
            <p className="page-subheader">Review and triage staff and student absences</p>

            <div className="flex items-center gap-3 mb-6">
                <div className="relative flex-1 max-w-md">
                    <Search className="w-4 h-4 text-slate-400 absolute left-3 top-1/2 -translate-y-1/2" />
                    <input
                        type="text"
                        placeholder="Search applicant or reason..."
                        value={search}
                        onChange={e => setSearch(e.target.value)}
                        className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-2 text-white text-sm placeholder-slate-500 focus:outline-none focus:border-blue-500/50 transition-colors"
                    />
                </div>
            </div>

            <div className="space-y-4 fade-in">
                {filtered.length === 0 ? (
                    <div className="glass-card p-12 text-center">
                        <CheckCircle className="w-12 h-12 text-emerald-500/50 mx-auto mb-4" />
                        <p className="text-white font-medium text-lg">Queue Empty</p>
                        <p className="text-slate-400 mt-1">No pending leave requests found across the campus.</p>
                    </div>
                ) : (
                    filtered.map(r => (
                        <div key={r.id} className="glass-card p-5 hover:border-white/20 transition-all flex flex-col md:flex-row gap-4 items-start md:items-center">
                            <div className={`w-12 h-12 rounded-full flex items-center justify-center flex-shrink-0 border font-bold text-lg
                                ${r.role === 'faculty' ? 'bg-purple-500/10 border-purple-500/20 text-purple-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}>
                                {r.applicant.charAt(0)}
                            </div>
                            <div className="flex-1 min-w-0">
                                <h4 className="text-white font-medium">{r.applicant} <span className="text-slate-500 text-xs font-normal capitalize">· {r.role}</span></h4>
                                <p className="text-slate-300 text-sm mt-1 mb-1.5">"{r.reason}"</p>
                                <p className="text-slate-500 text-xs flex items-center gap-1.5">
                                    <CalendarClock className="w-3.5 h-3.5" />
                                    {formatDate(r.startDate)} {r.startDate !== r.endDate ? `to ${formatDate(r.endDate)}` : ''}
                                </p>
                            </div>
                            <div className="flex gap-2 w-full md:w-auto">
                                <button onClick={() => handleAction(r.id, "rejected")} className="flex-1 md:flex-none px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 text-sm font-medium rounded-xl border border-red-500/20 transition-colors">
                                    Decline
                                </button>
                                <button onClick={() => handleAction(r.id, "approved")} className="flex-1 md:flex-none px-4 py-2 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 text-sm font-medium rounded-xl border border-emerald-500/20 transition-colors">
                                    Approve
                                </button>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </DashboardLayout>
    );
}

"use client";

import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Users, Search, Plus, Filter, MoreVertical, Edit2, Trash2, Mail } from "lucide-react";
import React, { useState } from "react";
const DEMO_ALL_USERS = [
    { id: 1, name: "Arjun Sharma", role: "Student", dept: "CSE", status: "Active", email: "student@college.edu", joined: "Aug 2024" },
    { id: 2, name: "Priya Patel", role: "Student", dept: "CSE", status: "Active", email: "priya@college.edu", joined: "Aug 2024" },
    { id: 3, name: "Dr. Priya Mehta", role: "Faculty", dept: "CSE", status: "Active", email: "faculty@college.edu", joined: "Jan 2020" },
    { id: 4, name: "Prof. Rajan Kumar", role: "Faculty", dept: "ECE", status: "On Leave", email: "rajan@college.edu", joined: "Jul 2018" },
    { id: 5, name: "Rahul Verma", role: "Student", dept: "IT", status: "Suspended", email: "rahul@college.edu", joined: "Aug 2023" },
];

const UserRow = React.memo(({ user }: { user: typeof DEMO_ALL_USERS[0] }) => {
    return (
        <tr className="border-b border-white/5 hover:bg-white/[0.02] transition-colors group">
            <td className="p-4">
                <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-gradient-to-br from-blue-600/20 to-purple-600/20 border border-white/10 flex items-center justify-center text-white font-medium flex-shrink-0">
                        {user.name.charAt(0)}
                    </div>
                    <div>
                        <p className="text-white font-medium">{user.name}</p>
                        <p className="text-slate-400 text-xs">{user.email}</p>
                    </div>
                </div>
            </td>
            <td className="p-4">
                <div className="flex items-center gap-1.5">
                    <Users className={`w-3.5 h-3.5 ${user.role === 'Student' ? 'text-blue-400' : 'text-purple-400'}`} />
                    <span className="text-slate-300">{user.role}</span>
                </div>
            </td>
            <td className="p-4 text-slate-300">{user.dept}</td>
            <td className="p-4">
                <span className={`px-2.5 py-1 text-xs rounded-full font-medium ${user.status === 'Active' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' :
                    user.status === 'On Leave' ? 'bg-amber-500/10 text-amber-400 border border-amber-500/20' :
                        'bg-red-500/10 text-red-400 border border-red-500/20'
                    }`}>
                    {user.status}
                </span>
            </td>
            <td className="p-4">
                <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button className="p-1.5 text-slate-400 hover:text-blue-400 hover:bg-blue-400/10 rounded-lg transition-colors" title="Message">
                        <Mail className="w-4 h-4" />
                    </button>
                    <button className="p-1.5 text-slate-400 hover:text-emerald-400 hover:bg-emerald-400/10 rounded-lg transition-colors" title="Edit">
                        <Edit2 className="w-4 h-4" />
                    </button>
                    <button className="p-1.5 text-slate-400 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-colors" title="Delete">
                        <Trash2 className="w-4 h-4" />
                    </button>
                </div>
            </td>
        </tr>
    );
});
UserRow.displayName = "UserRow";

export default function ManageUsersPage() {
    const [searchTerm, setSearchTerm] = useState("");
    const [activeTab, setActiveTab] = useState("All");

    const filteredUsers = DEMO_ALL_USERS.filter(user => {
        const matchesSearch = user.name.toLowerCase().includes(searchTerm.toLowerCase()) || user.email.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesTab = activeTab === "All" || user.role === activeTab;
        return matchesSearch && matchesTab;
    });

    return (
        <DashboardLayout role="coordinator" title="Manage Users">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-8 fade-in">
                <div>
                    <h1 className="text-3xl font-bold text-white mb-1">User Management</h1>
                    <p className="text-slate-400 text-sm">View, add, and manage all students and faculty in the system.</p>
                </div>
                <button className="btn-primary flex items-center gap-2">
                    <Plus className="w-4 h-4" /> Add New User
                </button>
            </div>

            <div className="glass-card p-6 fade-in" style={{ animationDelay: "100ms" }}>
                {/* Controls */}
                <div className="flex flex-col md:flex-row justify-between gap-4 mb-6">
                    <div className="flex bg-white/5 p-1 rounded-xl border border-white/10 w-fit">
                        {["All", "Student", "Faculty"].map(tab => (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-300 ${activeTab === tab ? "bg-blue-600/20 text-blue-400 shadow-[inset_0_1px_0_0_rgba(255,255,255,0.1)]" : "text-slate-400 hover:text-white hover:bg-white/5"}`}
                            >
                                {tab}
                            </button>
                        ))}
                    </div>

                    <div className="flex gap-2">
                        <div className="relative">
                            <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input
                                type="text"
                                placeholder="Search users..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="bg-white/5 border border-white/10 rounded-xl pl-9 pr-4 py-2 text-sm text-white placeholder-slate-500 focus:outline-none focus:border-blue-500/50 w-full md:w-64 transition-all"
                            />
                        </div>
                        <button className="p-2 bg-white/5 border border-white/10 rounded-xl text-slate-400 hover:text-white transition-colors">
                            <Filter className="w-4 h-4" />
                        </button>
                    </div>
                </div>

                {/* Table */}
                <div className="overflow-x-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="border-b border-white/10 text-slate-400 text-xs uppercase tracking-wider">
                                <th className="p-4 font-medium">Name</th>
                                <th className="p-4 font-medium">Role</th>
                                <th className="p-4 font-medium">Department</th>
                                <th className="p-4 font-medium">Status</th>
                                <th className="p-4 text-right font-medium">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="text-sm">
                            {filteredUsers.map((user) => (
                                <UserRow key={user.id} user={user} />
                            ))}
                        </tbody>
                    </table>

                    {filteredUsers.length === 0 && (
                        <div className="py-12 text-center text-slate-400">
                            No users found matching your criteria.
                        </div>
                    )}
                </div>
            </div>
        </DashboardLayout>
    );
}

"use client";

import { useState } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_ASSIGNMENTS } from "@/lib/demo-data";
import { BookOpen, Plus, Search, MapPin, CheckCircle, Clock } from "lucide-react";
import { formatDate } from "@/lib/utils";

export default function FacultyAssignmentsPage() {
    const [assignments, setAssignments] = useState(DEMO_ASSIGNMENTS);
    const [title, setTitle] = useState("");
    const [subject, setSubject] = useState("Data Structures");
    const [date, setDate] = useState("");
    const [search, setSearch] = useState("");

    const handleCreate = (e: React.FormEvent) => {
        e.preventDefault();
        if (!title || !date) return;

        const newAssignment = {
            id: `a-${Date.now()}`,
            title,
            subject,
            dueDate: date,
            status: "pending",
            faculty: "Dr. Priya Mehta"
        };

        setAssignments(prev => [newAssignment, ...prev]);
        setTitle("");
        setDate("");
    };

    const filtered = assignments.filter(a =>
        a.title.toLowerCase().includes(search.toLowerCase()) ||
        a.subject.toLowerCase().includes(search.toLowerCase())
    );

    return (
        <DashboardLayout role="faculty" title="Assignments">
            <div className="page-header">Assignment Management</div>
            <p className="page-subheader">Create and track student assignments</p>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                    <div className="glass-card p-5 sticky top-24">
                        <h3 className="text-white font-semibold mb-4 flex items-center gap-2">
                            <Plus className="w-5 h-5 text-blue-400" />
                            New Assignment
                        </h3>
                        <form onSubmit={handleCreate} className="space-y-4">
                            <div>
                                <label className="text-xs text-slate-400 mb-1 block">Title</label>
                                <input type="text" value={title} onChange={e => setTitle(e.target.value)}
                                    placeholder="e.g. Graph Traversal..."
                                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-white text-sm placeholder-slate-500 focus:outline-none focus:border-blue-500/50 transition-colors" />
                            </div>
                            <div>
                                <label className="text-xs text-slate-400 mb-1 block">Subject</label>
                                <select value={subject} onChange={e => setSubject(e.target.value)}
                                    className="w-full bg-white/5 border border-white/10 rounded-xl px-3 py-2.5 text-white text-sm focus:outline-none focus:border-blue-500/50 transition-colors">
                                    <option value="Data Structures" className="bg-slate-900">Data Structures</option>
                                    <option value="Algorithms" className="bg-slate-900">Algorithms</option>
                                    <option value="DBMS" className="bg-slate-900">DBMS</option>
                                </select>
                            </div>
                            <div>
                                <label className="text-xs text-slate-400 mb-1 block">Due Date</label>
                                <input type="date" value={date} onChange={e => setDate(e.target.value)}
                                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-white text-sm focus:outline-none focus:border-blue-500/50 transition-colors" />
                            </div>
                            <button type="submit" className="w-full btn-primary py-2.5 text-sm">
                                Create Assignment
                            </button>
                        </form>
                    </div>
                </div>

                <div className="lg:col-span-2">
                    <div className="flex items-center gap-3 mb-4">
                        <div className="relative flex-1">
                            <Search className="w-4 h-4 text-slate-400 absolute left-3 top-1/2 -translate-y-1/2" />
                            <input
                                type="text"
                                placeholder="Search assignments..."
                                value={search}
                                onChange={e => setSearch(e.target.value)}
                                className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-2 text-white text-sm placeholder-slate-500 focus:outline-none focus:border-blue-500/50 transition-colors"
                            />
                        </div>
                    </div>

                    <div className="space-y-3">
                        {filtered.length === 0 ? (
                            <div className="glass-card p-10 text-center">
                                <BookOpen className="w-8 h-8 text-slate-600 mx-auto mb-3" />
                                <p className="text-slate-400">No assignments found</p>
                            </div>
                        ) : (
                            filtered.map(a => (
                                <div key={a.id} className="glass-card p-4 hover:border-white/20 transition-all flex flex-col md:flex-row gap-4 items-start md:items-center">
                                    <div className="w-12 h-12 rounded-xl bg-blue-500/10 flex items-center justify-center flex-shrink-0 border border-blue-500/20">
                                        <BookOpen className="w-5 h-5 text-blue-400" />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className="text-white font-medium text-base truncate">{a.title}</p>
                                        <p className="text-slate-400 text-sm">{a.subject}</p>
                                        <div className="flex items-center gap-3 mt-2 text-xs">
                                            <span className="flex items-center gap-1 text-slate-500">
                                                <Clock className="w-3.5 h-3.5" /> Due {formatDate(a.dueDate)}
                                            </span>
                                        </div>
                                    </div>
                                    <div className="flex flex-row md:flex-col gap-2 w-full md:w-auto">
                                        <button className="flex-1 md:flex-none px-4 py-1.5 bg-white/5 hover:bg-white/10 text-white text-xs font-medium rounded-lg border border-white/10 transition-colors">
                                            Edit
                                        </button>
                                        <button className="flex-1 md:flex-none px-4 py-1.5 bg-blue-500/10 hover:bg-blue-500/20 text-blue-400 text-xs font-medium rounded-lg border border-blue-500/20 transition-colors">
                                            View Submissions
                                        </button>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            </div>
        </DashboardLayout>
    );
}

"use client";

import { useState } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_LEAVES } from "@/lib/demo-data";
import { useAuth } from "@/lib/auth-context";
import { CalendarClock, CheckCircle, XCircle, Clock, Plus, Filter } from "lucide-react";
import { formatDate } from "@/lib/utils";

export default function FacultyLeavesPage() {
    const { userProfile } = useAuth();

    // Split into faculty's own leaves vs student leaves requesting approval
    const [myLeaves, setMyLeaves] = useState(DEMO_LEAVES.filter(l => l.role === "faculty" && l.applicant === (userProfile?.name || "Dr. Priya Mehta")));
    const [studentRequests, setStudentRequests] = useState(DEMO_LEAVES.filter(l => l.role === "student" && l.status === "pending"));
    const [tab, setTab] = useState<"my-leaves" | "approvals">("approvals");

    // Form states
    const [startDate, setStartDate] = useState("");
    const [endDate, setEndDate] = useState("");
    const [reason, setReason] = useState("");

    const handleApply = (e: React.FormEvent) => {
        e.preventDefault();
        if (!startDate || !endDate || !reason) return;

        const newLeave = {
            id: `l-${Date.now()}`,
            applicant: userProfile?.name || "Dr. Priya Mehta",
            role: "faculty",
            startDate,
            endDate,
            reason,
            status: "pending"
        };

        setMyLeaves(prev => [newLeave, ...prev]);
        setStartDate("");
        setEndDate("");
        setReason("");
        setTab("my-leaves");
    };

    const handleAction = (id: string, action: "approved" | "rejected") => {
        setStudentRequests(prev => prev.filter(r => r.id !== id));
        // In reality, updates DB.
    };

    return (
        <DashboardLayout role="faculty" title="Leave Management">
            <div className="page-header">Leaves & Approvals</div>
            <p className="page-subheader">Manage student leaves and apply for your own</p>

            <div className="flex gap-2 mb-6 border-b border-white/10 pb-px">
                <button
                    onClick={() => setTab("approvals")}
                    className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 ${tab === "approvals" ? "text-blue-400 border-blue-400" : "text-slate-400 border-transparent hover:text-white"}`}
                >
                    Student Approvals {studentRequests.length > 0 && <span className="ml-1.5 bg-blue-500 text-white text-[10px] px-1.5 py-0.5 rounded-full">{studentRequests.length}</span>}
                </button>
                <button
                    onClick={() => setTab("my-leaves")}
                    className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 ${tab === "my-leaves" ? "text-purple-400 border-purple-400" : "text-slate-400 border-transparent hover:text-white"}`}
                >
                    My Leave History
                </button>
            </div>

            {tab === "approvals" && (
