                </div>
            )}
        </DashboardLayout>
    );
}

"use client";

import { useState, useEffect } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_NOTICES } from "@/lib/demo-data";
import { formatDate } from "@/lib/utils";
import { useAuth } from "@/lib/auth-context";
import { db } from "@/lib/firebase";
import { collection, addDoc, onSnapshot, query, orderBy, deleteDoc, doc, serverTimestamp } from "firebase/firestore";
import { Send, Trash2 } from "lucide-react";

export default function FacultyNoticesPage() {
    const { userProfile } = useAuth();
    const [notices, setNotices] = useState<typeof DEMO_NOTICES>(DEMO_NOTICES);
    const [title, setTitle] = useState("");
    const [body, setBody] = useState("");
    const [type, setType] = useState("general");
    const [target, setTarget] = useState("all");
    const [submitted, setSubmitted] = useState(false);
    const [isUsingFallback, setIsUsingFallback] = useState(false);

    useEffect(() => {
        // Attempt to listen to real Firestore updates
        try {
            const q = query(collection(db, "notices"), orderBy("date", "desc"));
            const unsubscribe = onSnapshot(q, (snapshot) => {
                const fetchedNotices = snapshot.docs.map(doc => ({
                    id: doc.id,
                    ...doc.data(),
                    // Handle Firestore timestamps correctly into an ISO string or fallback to now
                    date: doc.data().date?.toDate?.()?.toISOString() || new Date().toISOString()
                })) as typeof DEMO_NOTICES;
                if (fetchedNotices.length > 0) {
                    setNotices(fetchedNotices);
                    setIsUsingFallback(false);
                } else {
                    // Empty DB scenario: show demo strictly for visual testing if DB is empty but connected
                    setNotices(DEMO_NOTICES);
                    setIsUsingFallback(true);
                }
            }, (error) => {
                console.warn("Firestore listener failed, using demo data fallback.", error);
                setTimeout(() => {
                    setNotices(DEMO_NOTICES);
                    setIsUsingFallback(true);
                }, 0);
            });

            return () => unsubscribe();
        } catch (error) {
            console.warn("Firestore connection failed.");
            setTimeout(() => {
                setNotices(DEMO_NOTICES);
                setIsUsingFallback(true);
            }, 0);
        }
    }, []);

    const handlePost = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!title || !body) return;

        try {
            // Attempt real write
            await addDoc(collection(db, "notices"), {
                title,
                body,
                type,
                target,
                author: userProfile?.name || "Faculty Member",
                date: serverTimestamp() // Set exact server time natively
            });
            setSubmitted(true);
            setTimeout(() => { setTitle(""); setBody(""); setSubmitted(false); }, 3000);
        } catch (error) {
            console.error("Failed to post notice to DB:", error);
            // Fallback: mock a visual post if Firebase is down
            if (isUsingFallback) {
                const newNotice = {
                    id: `mock-${Date.now()}`,
                    title,
                    body,
                    type,
                    author: userProfile?.name || "Faculty Member",
                    date: new Date().toISOString()
                };
                setNotices(prev => [newNotice, ...prev]);
                setSubmitted(true);
                setTimeout(() => { setTitle(""); setBody(""); setSubmitted(false); }, 3000);
            }
        }
    };

    const handleDelete = async (id: string) => {
        try {
            if (!id.startsWith("mock-")) {
                await deleteDoc(doc(db, "notices", id));
            } else {
                setNotices(prev => prev.filter(n => n.id !== id));
            }
        } catch (error) {
            console.error("Failed to delete from DB:", error);
        }
    };

    return (
        <DashboardLayout role="faculty" title="Notices">
            <div className="page-header">Post Notices</div>
            <p className="page-subheader">Broadcast announcements to students</p>

            {/* Post form */}
            <div className="glass-card p-5 mb-6 fade-in">
                <h3 className="text-white font-semibold mb-4">New Announcement</h3>
                <form onSubmit={handlePost} className="space-y-3">
                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="text-xs text-slate-400 mb-1 block">Category</label>
                            <select value={type} onChange={e => setType(e.target.value)}
                                className="w-full bg-white/5 border border-white/10 rounded-xl px-3 py-2.5 text-white text-sm focus:outline-none focus:border-blue-500/50 transition-colors">
                                {["general", "exam", "assignment", "event", "holiday"].map(t => (
                                    <option key={t} value={t} className="bg-slate-900 capitalize">{t.charAt(0).toUpperCase() + t.slice(1)}</option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="text-xs text-slate-400 mb-1 block">Target Audience</label>
                            <select value={target} onChange={e => setTarget(e.target.value)}
                                className="w-full bg-white/5 border border-white/10 rounded-xl px-3 py-2.5 text-white text-sm focus:outline-none focus:border-blue-500/50 transition-colors">
                                <option value="all" className="bg-slate-900">All Students</option>
                                <option value="CS-4A" className="bg-slate-900">CS-4A Only</option>
                                <option value="CS-4B" className="bg-slate-900">CS-4B Only</option>
                            </select>
                        </div>
                    </div>

                    <div>
                        <label className="text-xs text-slate-400 mb-1 block">Title</label>
                        <input type="text" value={title} onChange={e => setTitle(e.target.value)}
                            placeholder="Notice title..."
                            className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-white text-sm placeholder-slate-500 focus:outline-none focus:border-blue-500/50 transition-colors" />
                    </div>

                    <div>
                        <label className="text-xs text-slate-400 mb-1 block">Message</label>
                        <textarea value={body} onChange={e => setBody(e.target.value)}
                            placeholder="Write your announcement here..."
                            rows={4}
                            className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white text-sm placeholder-slate-500 focus:outline-none focus:border-blue-500/50 transition-colors resize-none" />
                    </div>

                    <button type="submit"
                        className={`flex items-center gap-2 btn-primary text-sm px-6 py-2.5 transition-all ${submitted ? "!from-emerald-600 !to-teal-600 !shadow-emerald-500/25" : ""
                            }`}>
                        {submitted ? "✓ Notice Posted!" : <><Send className="w-4 h-4" />Post Notice</>}
                    </button>
                </form>
            </div>

            {/* Previous notices */}
            <h3 className="text-white font-semibold mb-3 fade-in">Previous Notices</h3>
            <div className="space-y-3 fade-in">
                {notices.map(notice => (
                    <div key={notice.id} className="glass-card p-4 flex items-start gap-3 hover:border-white/20 transition-all">
                        <div className="flex-1">
                            <div className="flex items-center gap-2 mb-1">
                                <span className="text-white text-sm font-medium">{notice.title}</span>
                                <span className={`text-xs px-2 py-0.5 rounded-full capitalize ${notice.type === "exam" ? "bg-purple-600/20 text-purple-400" :
                                    notice.type === "assignment" ? "bg-blue-600/20 text-blue-400" :
                                        notice.type === "event" ? "bg-amber-600/20 text-amber-400" :
                                            notice.type === "holiday" ? "bg-emerald-600/20 text-emerald-400" :
                                                "bg-slate-700/50 text-slate-400"
                                    }`}>{notice.type}</span>
                            </div>
                            <p className="text-slate-400 text-xs mb-1 line-clamp-2">{notice.body}</p>
                            <div className="flex items-center gap-2 text-xs text-slate-600">
                                <span>{notice.author}</span>
                                <span>·</span>
                                <span>{formatDate(notice.date)}</span>
                            </div>
                        </div>
                        <button onClick={() => handleDelete(notice.id)} className="text-slate-600 hover:text-red-400 transition-colors p-1 flex-shrink-0 cursor-pointer z-10">
                            <Trash2 className="w-4 h-4" />
                        </button>
                    </div>
                ))}
            </div>
        </DashboardLayout>
    );
}

"use client";

import { useState, useCallback, memo } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_STUDENTS, DEMO_RESULTS } from "@/lib/demo-data";
import { db } from "@/lib/firebase";
import { collection, addDoc, serverTimestamp } from "firebase/firestore";
import { Save } from "lucide-react";
import { cn } from "@/lib/utils";

const StudentRow = memo(({ student, index, mark, onUpdateMark, getGrade }: any) => {
    const internal = parseInt(mark?.internal || "0");
    const external = parseInt(mark?.external || "0");
    const total = internal + external;
    const grade = getGrade(total);

    return (
        <div className="px-4 py-3 flex items-center gap-3 hover:bg-white/3 transition-colors">
            <div className="w-7 h-7 rounded-full bg-amber-600/30 flex items-center justify-center text-amber-300 text-xs font-bold flex-shrink-0">
                {index + 1}
            </div>
            <div className="flex-1 min-w-0">
                <p className="text-white text-sm font-medium truncate">{student.name}</p>
                <p className="text-slate-500 text-xs font-mono">{student.rollNumber}</p>
            </div>
            <div className="flex items-center gap-2 flex-shrink-0">
                <input
                    type="number" min="0" max="50"
                    value={mark?.internal || ""}
                    onChange={e => onUpdateMark(student.rollNumber, 'internal', e.target.value)}
                    placeholder="Int."
                    className="w-14 bg-white/5 border border-white/10 rounded-lg px-2 py-1.5 text-white text-xs text-center focus:outline-none focus:border-amber-500/50 transition-colors"
                />
                <input
                    type="number" min="0" max="100"
                    value={mark?.external || ""}
                    onChange={e => onUpdateMark(student.rollNumber, 'external', e.target.value)}
                    placeholder="Ext."
                    className="w-14 bg-white/5 border border-white/10 rounded-lg px-2 py-1.5 text-white text-xs text-center focus:outline-none focus:border-amber-500/50 transition-colors"
                />
                <div className={`w-10 text-center font-bold text-sm transition-colors ${total >= 105 ? "text-emerald-400" : total >= 75 ? "text-blue-400" : "text-red-400"}`}>
                    {grade}
                </div>
            </div>
        </div>
    );
});
StudentRow.displayName = "StudentRow";

export default function FacultyResultsPage() {
    const [selectedSubject, setSelectedSubject] = useState("Data Structures");
    const [marks, setMarks] = useState<Record<string, { internal: string; external: string }>>(
        Object.fromEntries(DEMO_STUDENTS.map(s => [
            s.rollNumber,
            { internal: String(DEMO_RESULTS[0]?.internal || "0"), external: String(DEMO_RESULTS[0]?.external || "0") },
        ]))
    );
    const [saved, setSaved] = useState(false);
    const [isSaving, setIsSaving] = useState(false);

    const subjects = ["Data Structures", "DBMS", "Algorithms"];

    const handleUpdateMark = useCallback((rollNumber: string, type: 'internal' | 'external', value: string) => {
        setMarks(prev => ({
            ...prev,
            [rollNumber]: { ...prev[rollNumber], [type]: value }
        }));
        setSaved(false);
    }, []);

    const getGrade = useCallback((total: number, max: number = 150) => {
        const pct = (total / max) * 100;
        if (pct >= 90) return "A+";
        if (pct >= 80) return "A";
        if (pct >= 70) return "B+";
        if (pct >= 60) return "B";
        if (pct >= 50) return "C";
        return "F";
    }, []);

    const handleSave = async () => {
        setIsSaving(true);
        setSaved(false);

        try {
            const promises = Object.entries(marks).map(([roll, m]) => {
                const int = parseInt(m.internal || "0");
                const ext = parseInt(m.external || "0");
                const max = 150;

                return addDoc(collection(db, "results"), {
                    rollNumber: roll,
                    subject: selectedSubject,
                    internal: int,
                    external: ext,
                    total: int + ext,
                    max: max,
                    grade: getGrade(int + ext, max),
                    date: serverTimestamp(),
                    dateString: new Date().toISOString().split("T")[0]
                });
            });

            await Promise.all(promises);
            setSaved(true);
        } catch (error) {
            console.error("Failed to push real results data. Falling back to mock UI...", error);
            setTimeout(() => setSaved(true), 400);
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <DashboardLayout role="faculty" title="Results">
            <div className="page-header">Marks & Results</div>
            <p className="page-subheader">Upload internal and external marks for your subjects</p>

            {/* Subject selector */}
            <div className="glass-card p-4 mb-5 fade-in">
                <p className="text-slate-400 text-xs mb-2 uppercase tracking-wider">Select Subject</p>
                <div className="flex gap-2 flex-wrap">
                    {subjects.map(sub => (
                        <button key={sub} onClick={() => { setSelectedSubject(sub); setSaved(false); }}
                            className={`px-4 py-2 rounded-xl text-sm font-medium transition-all ${selectedSubject === sub
                                ? "bg-gradient-to-r from-amber-600 to-orange-600 text-white shadow-lg shadow-amber-500/25"
                                : "bg-white/5 text-slate-400 hover:text-white hover:bg-white/10"
                                }`}>
                            {sub}
                        </button>
                    ))}
                </div>
            </div>

            {/* Marks table */}
            <div className="glass-card overflow-hidden mb-4 fade-in">
                <div className="px-5 py-4 border-b border-white/5 flex items-center justify-between">
                    <p className="text-white font-semibold">{selectedSubject} — CS-4A</p>
                    <p className="text-xs text-slate-500">Internal: /50 · External: /100 · Total: /150</p>
                </div>
                <div className="divide-y divide-white/5">
                    {DEMO_STUDENTS.map((student, i) => (
                        <StudentRow
                            key={student.rollNumber}
                            student={student}
                            index={i}
                            mark={marks[student.rollNumber]}
                            onUpdateMark={handleUpdateMark}
                            getGrade={getGrade}
                        />
                    ))}
                </div>
            </div>

            <button
                onClick={handleSave}
                disabled={isSaving}
                className={cn(
                    "w-full flex items-center justify-center gap-2 p-4 rounded-2xl font-semibold text-sm transition-all duration-300 fade-in",
                    saved
                        ? "bg-emerald-600/20 border border-emerald-500/20 text-emerald-400"
                        : "bg-gradient-to-r from-amber-600 to-orange-600 text-white shadow-lg shadow-amber-500/25",
                    isSaving ? "opacity-75 cursor-wait" : ""
                )}
            >
                {isSaving ? (
                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : saved ? "✓ Marks Saved Successfully!" : <><Save className="w-4 h-4" />Save Marks</>}
            </button>
        </DashboardLayout>
    );
}

