"use client";

import { useState, useEffect } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_ATTENDANCE } from "@/lib/demo-data";
import { getAttendanceColor, getAttendanceBg } from "@/lib/utils";
import { useAuth } from "@/lib/auth-context";
import { db } from "@/lib/firebase";
import { collection, query, where, onSnapshot } from "firebase/firestore";
import { AlertTriangle, CheckCircle, Info } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from "recharts";

type AggregatedAttendance = {
    subject: string;
    present: number;
    total: number;
    percent: number;
};

export default function AttendancePage() {
    const { userProfile } = useAuth();
    const [attendanceData, setAttendanceData] = useState<AggregatedAttendance[]>(DEMO_ATTENDANCE);

    useEffect(() => {
        if (!userProfile?.rollNumber) return;

        try {
            const q = query(
                collection(db, "attendance"),
                where("rollNumber", "==", userProfile.rollNumber)
            );

            const unsubscribe = onSnapshot(q, (snapshot) => {
                if (snapshot.empty) {
                    setAttendanceData(DEMO_ATTENDANCE);
                    return;
                }

                // Aggregate raw records by subject
                const tally: Record<string, { present: number; total: number }> = {};
                snapshot.docs.forEach((doc) => {
                    const data = doc.data();
                    const sub = data.subject as string;
                    if (!tally[sub]) tally[sub] = { present: 0, total: 0 };

                    tally[sub].total++;
                    if (data.status === "present") tally[sub].present++;
                });

                const aggregated: AggregatedAttendance[] = Object.keys(tally).map((sub) => {
                    const t = tally[sub];
                    return {
                        subject: sub,
                        present: t.present,
                        total: t.total,
                        percent: t.total > 0 ? Math.round((t.present / t.total) * 100) : 0
                    };
                });

                if (aggregated.length > 0) {
                    setAttendanceData(aggregated);
                } else {
                    setAttendanceData(DEMO_ATTENDANCE);
                }
            }, (err) => {
                console.warn("Firestore listener failed, using demo fallback.", err);
                setTimeout(() => setAttendanceData(DEMO_ATTENDANCE), 0);
            });

            return () => unsubscribe();
        } catch (error) {
            console.warn("Firestore connection failed.");
            setTimeout(() => setAttendanceData(DEMO_ATTENDANCE), 0);
        }
    }, [userProfile?.rollNumber]);

    const avg = attendanceData.length > 0
        ? Math.round(attendanceData.reduce((s, a) => s + a.percent, 0) / attendanceData.length)
        : 0;

    const chartData = attendanceData.map(a => ({ name: a.subject.split(" ")[0], pct: a.percent }));

    return (
        <DashboardLayout role="student" title="Attendance">
            <div className="page-header">Attendance</div>
            <p className="page-subheader">Track your attendance across all subjects</p>

            {/* Overall */}
            <div className="glass-card p-5 mb-6 fade-in">
                <div className="flex items-center justify-between flex-wrap gap-4">
                    <div>
                        <p className="text-slate-400 text-sm mb-1">Overall Attendance</p>
                        <p className={`text-5xl font-bold ${getAttendanceColor(avg)}`}>{avg}%</p>
                        <p className="text-slate-500 text-xs mt-1">Across {attendanceData.length} subjects</p>
                    </div>
                    <div className="space-y-2 text-sm">
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 rounded-full bg-emerald-500" />
                            <span className="text-slate-400">≥75% — Safe</span>
                        </div>
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 rounded-full bg-amber-500" />
                            <span className="text-slate-400">60–74% — Warning</span>
                        </div>
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 rounded-full bg-red-500" />
                            <span className="text-slate-400">&lt;60% — Critical</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Bar chart */}
            <div className="glass-card p-5 mb-6 fade-in">
                <h3 className="text-white font-semibold mb-4">Subject-wise Overview</h3>
                <ResponsiveContainer width="100%" height={200}>
                    <BarChart data={chartData} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                        <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" />
                        <XAxis dataKey="name" tick={{ fill: "#94a3b8", fontSize: 11 }} />
                        <YAxis tick={{ fill: "#94a3b8", fontSize: 11 }} domain={[0, 100]} />
                        <Tooltip
                            contentStyle={{ background: "#1e293b", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 12 }}
                            labelStyle={{ color: "#fff" }}
                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                            formatter={(val: any) => [`${val}%`, "Attendance"]}
                        />
                        <Bar dataKey="pct" radius={[6, 6, 0, 0]}>
                            {chartData.map((entry, i) => (
                                <Cell key={i} fill={entry.pct >= 75 ? "#10b981" : entry.pct >= 60 ? "#f59e0b" : "#ef4444"} />
                            ))}
                        </Bar>
                    </BarChart>
                </ResponsiveContainer>
            </div>

            {/* Subject list */}
            <div className="space-y-3 fade-in">
                {attendanceData.map((subject, i) => (
                    <div key={i} className="glass-card p-4">
                        <div className="flex items-center justify-between mb-3">
                            <div className="flex items-center gap-2">
                                {subject.percent >= 75 ? (
                                    <CheckCircle className="w-4 h-4 text-emerald-400" />
                                ) : subject.percent >= 60 ? (
                                    <Info className="w-4 h-4 text-amber-400" />
                                ) : (
                                    <AlertTriangle className="w-4 h-4 text-red-400" />
                                )}
                                <span className="text-white font-medium text-sm">{subject.subject}</span>
                            </div>
                            <span className={`text-lg font-bold ${getAttendanceColor(subject.percent)}`}>
                                {subject.percent}%
                            </span>
                        </div>
                        <div className="w-full bg-white/5 rounded-full h-2 mb-2">
                            <div
                                className={`h-2 rounded-full progress-bar ${getAttendanceBg(subject.percent)}`}
                                style={{ width: `${subject.percent}%` }}
                            />
                        </div>
                        <div className="flex justify-between text-xs text-slate-500">
                            <span>{subject.present} classes attended</span>
                            <span>{subject.total} total classes</span>
                        </div>
                        {subject.percent < 75 && (
                            <div className="mt-2 text-xs bg-amber-500/10 border border-amber-500/20 text-amber-400 px-3 py-1.5 rounded-lg">
                                Need to attend {Math.ceil((0.75 * subject.total - subject.present) / (1 - 0.75))} more classes to reach 75%
                            </div>
                        )}
                    </div>
                ))}
            </div>
        </DashboardLayout>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useAuth } from "@/lib/auth-context";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_ATTENDANCE, DEMO_TIMETABLE, DEMO_EXAMS, DEMO_NOTICES } from "@/lib/demo-data";
import { getCurrentDay, getAttendanceColor, getDaysUntil, formatDate, getGreetingTime } from "@/lib/utils";
import { db } from "@/lib/firebase";
import { collection, onSnapshot, query, where } from "firebase/firestore";
import { Clock, TrendingUp, BookOpen, AlertTriangle, CalendarCheck, Bell, ChevronRight, MapPin, Award } from "lucide-react";
import Link from "next/link";

export default function StudentDashboard() {
    const { userProfile } = useAuth();
    const [noticeCount, setNoticeCount] = useState(DEMO_NOTICES.length);
    const [attendanceStats, setAttendanceStats] = useState({
        avg: Math.round(DEMO_ATTENDANCE.reduce((s, a) => s + a.percent, 0) / DEMO_ATTENDANCE.length),
        low: DEMO_ATTENDANCE.filter(a => a.percent < 75).length
    });
    const [greeting, setGreeting] = useState("");

    useEffect(() => {
        let unsubscribeNotices = () => { };
        let unsubscribeAttendance = () => { };

        setTimeout(() => setGreeting(getGreetingTime()), 0);
        const timeInterval = setInterval(() => setGreeting(getGreetingTime()), 60000);

        try {
            unsubscribeNotices = onSnapshot(collection(db, "notices"), (snapshot) => {
                if (!snapshot.empty) setNoticeCount(snapshot.docs.length);
            }, () => setNoticeCount(DEMO_NOTICES.length));

            if (userProfile?.rollNumber) {
                const q = query(
                    collection(db, "attendance"),
                    where("rollNumber", "==", userProfile.rollNumber)
                );
                unsubscribeAttendance = onSnapshot(q, (snapshot) => {
                    if (snapshot.empty) return;

                    const tally: Record<string, { present: number; total: number }> = {};
                    snapshot.docs.forEach((doc) => {
                        const data = doc.data();
                        const sub = data.subject as string;
                        if (!tally[sub]) tally[sub] = { present: 0, total: 0 };
                        tally[sub].total++;
                        if (data.status === "present") tally[sub].present++;
                    });

                    const aggregated = Object.values(tally).map(t =>
                        t.total > 0 ? Math.round((t.present / t.total) * 100) : 0
                    );

                    if (aggregated.length > 0) {
                        setAttendanceStats({
                            avg: Math.round(aggregated.reduce((s, p) => s + p, 0) / aggregated.length),
                            low: aggregated.filter(p => p < 75).length
                        });
                    }
                }, () => { });
            }

        } catch {
            setNoticeCount(DEMO_NOTICES.length);
            // Attendance stats stay gracefully on DEMO defaults
        }

        return () => {
            unsubscribeNotices();
            unsubscribeAttendance();
            clearInterval(timeInterval);
        };
    }, [userProfile?.rollNumber]);

    const today = getCurrentDay();
    const todayClasses = DEMO_TIMETABLE[today] || [];
    const now = new Date();
    const currentHour = now.getHours();
    const currentMin = now.getMinutes();
    const avgAttendance = attendanceStats.avg;
    const lowAttendance = attendanceStats.low;
    const upcomingExams = DEMO_EXAMS.filter(e => getDaysUntil(e.date) > 0).slice(0, 3);

    // Find current/next class
    let currentClass = null;
    let nextClass = null;
    for (let i = 0; i < todayClasses.length; i++) {
        const cls = todayClasses[i];
        const [sh, sm] = cls.time.split(":").map(Number);
        const [eh, em] = cls.end.split(":").map(Number);
        const startMins = sh * 60 + sm;
        const endMins = eh * 60 + em;
        const nowMins = currentHour * 60 + currentMin;
        if (nowMins >= startMins && nowMins < endMins) { currentClass = cls; break; }
        if (nowMins < startMins && !nextClass) { nextClass = cls; }
    }

    return (
        <DashboardLayout role="student" title="Dashboard">
            {/* Welcome */}
            <div className="mb-6 fade-in">
                <h1 className="text-2xl lg:text-3xl font-bold text-white">
                    Good {greeting || getGreetingTime()},{" "}
                    <span className="gradient-text">{userProfile?.name?.split(" ")[0] || "Student"} 👋</span>
                </h1>
                <p className="text-slate-400 mt-1 text-sm">
                    {new Date().toLocaleDateString("en-IN", { weekday: "long", day: "numeric", month: "long", year: "numeric" })}
                </p>
            </div>

            {/* Current class banner */}
            {currentClass && (
                <div className="mb-6 p-4 rounded-2xl bg-gradient-to-r from-blue-600/20 to-indigo-600/20 border border-blue-500/20 flex items-center gap-4 fade-in">
                    <div className="w-10 h-10 rounded-xl bg-blue-600 flex items-center justify-center flex-shrink-0 pulse-glow">
                        <Clock className="w-5 h-5 text-white" />
                    </div>
                    <div className="flex-1">
                        <p className="text-xs text-blue-400 uppercase tracking-wider font-medium mb-0.5">🔴 Now in Class</p>
                        <p className="text-white font-semibold">{currentClass.subject}</p>
                        <p className="text-slate-400 text-xs">{currentClass.faculty} · Room {currentClass.room} · until {currentClass.end}</p>
                    </div>
                </div>
            )}

            {/* Stat cards */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 lg:gap-5 mb-8">
                <Link href="/student/attendance">
                    <div className="stat-card h-full">
                        <div className="flex items-center justify-between mb-2">
                            <span className="text-xs text-slate-300 uppercase tracking-wider font-semibold">Avg Attendance</span>
                            <div className="w-8 h-8 rounded-full bg-emerald-500/10 flex items-center justify-center">
                                <TrendingUp className="w-4 h-4 text-emerald-400" />
                            </div>
                        </div>
                        <p className={`text-4xl font-bold ${getAttendanceColor(avgAttendance)} my-1`}>{avgAttendance}%</p>
                        {lowAttendance > 0 ? (
                            <p className="text-xs text-amber-400 flex items-center gap-1.5 mt-auto pt-2 border-t border-white/5">
                                <AlertTriangle className="w-3.5 h-3.5" />{lowAttendance} subject{lowAttendance > 1 ? "s" : ""} low
                            </p>
                        ) : (
                            <p className="text-xs text-slate-400 flex items-center gap-1.5 mt-auto pt-2 border-t border-white/5">
                                On track
                            </p>
                        )}
                    </div>
                </Link>

                <Link href="/student/today-schedule">
                    <div className="stat-card h-full">
                        <div className="flex items-center justify-between mb-2">
                            <span className="text-xs text-slate-300 uppercase tracking-wider font-semibold">Classes Today</span>
                            <div className="w-8 h-8 rounded-full bg-blue-500/10 flex items-center justify-center">
                                <Clock className="w-4 h-4 text-blue-400" />
                            </div>
                        </div>
                        <p className="text-4xl font-bold text-blue-400 my-1">{todayClasses.length}</p>
                        <p className="text-xs text-slate-400 mt-auto pt-2 border-t border-white/5 truncate">
                            {nextClass ? `Next: ${nextClass.time} (${nextClass.subject})` : "No more classes today"}
                        </p>
                    </div>
                </Link>

                <Link href="/student/exam-schedule">
                    <div className="stat-card h-full">
                        <div className="flex items-center justify-between mb-2">
                            <span className="text-xs text-slate-300 uppercase tracking-wider font-semibold">Upcoming Exams</span>
                            <div className="w-8 h-8 rounded-full bg-purple-500/10 flex items-center justify-center">
                                <CalendarCheck className="w-4 h-4 text-purple-400" />
                            </div>
                        </div>
                        <p className="text-4xl font-bold text-purple-400 my-1">{DEMO_EXAMS.length}</p>
                        <p className="text-xs text-slate-400 mt-auto pt-2 border-t border-white/5 truncate">
                            {upcomingExams[0] ? `Next in ${getDaysUntil(upcomingExams[0].date)}d (${upcomingExams[0].subject})` : "No upcoming exams"}
                        </p>
                    </div>
                </Link>

                <Link href="/student/notices">
                    <div className="stat-card h-full">
                        <div className="flex items-center justify-between mb-2">
                            <span className="text-xs text-slate-300 uppercase tracking-wider font-semibold">New Notices</span>
                            <div className="w-8 h-8 rounded-full bg-amber-500/10 flex items-center justify-center">
                                <Bell className="w-4 h-4 text-amber-400" />
                            </div>
                        </div>
                        <p className="text-4xl font-bold text-amber-400 my-1">{noticeCount}</p>
                        <p className="text-xs text-slate-400 mt-auto pt-2 border-t border-white/5 truncate">
                            Recent college announcements
                        </p>
                    </div>
                </Link>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-5 mb-8 items-stretch">
                {/* Today's schedule summary */}
                <div className="glass-card p-6 fade-in flex flex-col h-full hidden-scrollbar">
                    <div className="flex items-center justify-between mb-5">
                        <h3 className="text-white font-semibold text-lg flex items-center gap-2">
                            <Clock className="w-5 h-5 text-blue-400" />
                            Today&apos;s Schedule
                        </h3>
                        <Link href="/student/today-schedule" className="text-blue-400 text-xs flex items-center gap-1 hover:text-blue-300">
                            View all <ChevronRight className="w-3 h-3" />
                        </Link>
                    </div>
                    <div className="space-y-3 flex-1 overflow-y-auto pr-2 custom-scrollbar">
                        {todayClasses.slice(0, 4).map((cls, i) => {
                            const [sh, sm] = cls.time.split(":").map(Number);
                            const [eh, em] = cls.end.split(":").map(Number);
                            const startMins = sh * 60 + sm;
                            const endMins = eh * 60 + em;
                            const nowMins = currentHour * 60 + currentMin;
                            const isNow = nowMins >= startMins && nowMins < endMins;
                            const isDone = nowMins >= endMins;
                            return (
                                <div key={i} className={`flex items-center gap-4 p-3.5 rounded-2xl transition-all duration-300 ${isNow ? "bg-gradient-to-r from-blue-600/20 to-indigo-600/10 border border-blue-500/30 shadow-[0_0_15px_rgba(59,130,246,0.1)]" : "bg-white/[0.02] hover:bg-white/[0.04] border border-transparent"
                                    } ${isDone ? "opacity-50 grayscale" : ""}`}>
                                    <div className={`w-1.5 h-10 rounded-full flex-shrink-0 ${isNow ? "bg-blue-400 shadow-[0_0_10px_rgba(96,165,250,0.8)]" : isDone ? "bg-slate-600" : "bg-slate-500"
                                        }`} />
                                    <div className="flex-1 min-w-0">
                                        <p className={`text-sm font-semibold truncate ${isNow ? "text-blue-100" : "text-white"}`}>{cls.subject}</p>
                                        <p className="text-slate-400 text-xs mt-0.5 flex items-center gap-2">
                                            <span>{cls.time} – {cls.end}</span>
                                            <span className="w-1 h-1 rounded-full bg-slate-600"></span>
                                            <span>Room {cls.room}</span>
                                        </p>
                                    </div>
                                    {isNow && <span className="text-xs px-2.5 py-1 rounded-lg bg-blue-500/20 text-blue-300 font-medium border border-blue-500/20">Now</span>}
                                </div>
                            );
                        })}
                        {todayClasses.length === 0 && (
                            <div className="flex flex-col items-center justify-center py-8 text-center h-full">
                                <CalendarCheck className="w-10 h-10 text-slate-600 mb-3" />
                                <p className="text-slate-300 font-medium">No classes today 🎉</p>
                                <p className="text-slate-500 text-xs mt-1">Enjoy your free time!</p>
                            </div>
                        )}
                    </div>
                </div>

                {/* Upcoming Exams */}
                <div className="glass-card p-6 fade-in flex flex-col h-full hidden-scrollbar">
                    <div className="flex items-center justify-between mb-5">
                        <h3 className="text-white font-semibold text-lg flex items-center gap-2">
                            <CalendarCheck className="w-5 h-5 text-purple-400" />
                            Upcoming Exams
                        </h3>
                        <Link href="/student/exam-schedule" className="text-blue-400 text-xs flex items-center gap-1 hover:text-blue-300">
                            View all <ChevronRight className="w-3 h-3" />
                        </Link>
                    </div>
                    <div className="space-y-3 flex-1 overflow-y-auto pr-2 custom-scrollbar">
                        {upcomingExams.map(exam => {
                            const days = getDaysUntil(exam.date);
                            return (
                                <div key={exam.id} className="flex items-center gap-4 p-3.5 rounded-2xl bg-white/[0.02] hover:bg-white/[0.05] transition-colors border border-transparent hover:border-white/5">
                                    <div className={`w-12 h-12 rounded-xl flex flex-col items-center justify-center flex-shrink-0 text-white font-bold text-xs shadow-lg
                    ${days <= 3 ? "bg-gradient-to-br from-red-500 to-rose-600 shadow-red-500/20" : days <= 7 ? "bg-gradient-to-br from-amber-500 to-orange-600 shadow-amber-500/20" : "bg-gradient-to-br from-purple-500 to-indigo-600 shadow-purple-500/20"}`}>
                                        <span className="text-lg font-bold leading-none">{days}</span>
                                        <span className="text-[9px] uppercase tracking-wider opacity-80 mt-0.5">days</span>
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className="text-white text-sm font-semibold truncate">{exam.subject}</p>
                                        <p className="text-slate-400 text-xs mt-0.5 flex items-center gap-2">
                                            <span>{formatDate(exam.date)}</span>
                                            <span className="w-1 h-1 rounded-full bg-slate-600"></span>
                                            <span>{exam.time}</span>
                                        </p>
                                    </div>
                                </div>
                            );
                        })}
                        {upcomingExams.length === 0 && (
                            <div className="flex flex-col items-center justify-center py-8 text-center h-full">
                                <Award className="w-10 h-10 text-slate-600 mb-3" />
                                <p className="text-slate-300 font-medium">No upcoming exams</p>
                                <p className="text-slate-500 text-xs mt-1">Keep up the good work!</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Quick links */}
            <div className="glass-card p-6 fade-in mb-4">
                <h3 className="text-white font-semibold text-lg mb-5 flex items-center gap-2">
                    <TrendingUp className="w-5 h-5 text-emerald-400" />
                    Quick Actions
                </h3>
                <div className="flex overflow-x-auto gap-3 lg:gap-4 pb-2 hidden-scrollbar snap-x">
                    {[
                        { href: "/student/attendance", label: "Attendance", icon: "📊", glow: "group-hover:shadow-[0_0_20px_rgba(16,185,129,0.15)] group-hover:border-emerald-500/30" },
                        { href: "/student/timetable", label: "Timetable", icon: "📅", glow: "group-hover:shadow-[0_0_20px_rgba(59,130,246,0.15)] group-hover:border-blue-500/30" },
                        { href: "/student/exam-schedule", label: "Exams", icon: "📝", glow: "group-hover:shadow-[0_0_20px_rgba(168,85,247,0.15)] group-hover:border-purple-500/30" },
                        { href: "/student/seating-plan", label: "Seating", icon: "🗺️", glow: "group-hover:shadow-[0_0_20px_rgba(245,158,11,0.15)] group-hover:border-amber-500/30" },
                        { href: "/student/results", label: "Results", icon: "🏆", glow: "group-hover:shadow-[0_0_20px_rgba(234,179,8,0.15)] group-hover:border-yellow-500/30" },
                        { href: "/student/notices", label: "Notices", icon: "🔔", glow: "group-hover:shadow-[0_0_20px_rgba(239,68,68,0.15)] group-hover:border-red-500/30" },
                    ].map(item => (
                        <Link key={item.href} href={item.href} className="group outline-none min-w-[140px] flex-shrink-0 snap-start flex-1">
                            <div className={`flex flex-col items-center justify-center gap-3 p-5 rounded-2xl bg-white/[0.02] border border-white/[0.05] transition-all duration-300 ${item.glow} hover:bg-white/[0.04] h-full`}>
                                <span className="text-4xl transform group-hover:scale-110 group-hover:-translate-y-1 transition-all duration-300 drop-shadow-md">{item.icon}</span>
                                <span className="text-sm text-slate-300 font-medium text-center">{item.label}</span>
                            </div>
                        </Link>
                    ))}
                </div>
            </div>
        </DashboardLayout>
    );
}

"use client";

import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_EXAMS } from "@/lib/demo-data";
import { getDaysUntil, formatDate, formatTime } from "@/lib/utils";
import { CalendarDays, Clock, MapPin, BookOpen } from "lucide-react";

export default function ExamSchedulePage() {
    const sorted = [...DEMO_EXAMS].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    return (
        <DashboardLayout role="student" title="Exam Schedule">
            <div className="page-header">Exam Schedule</div>
            <p className="page-subheader">Mid-Semester Examinations · March 2026</p>

            {/* Banner */}
            <div className="glass-card p-5 mb-6 bg-gradient-to-r from-purple-600/20 to-indigo-600/20 border-purple-500/20 fade-in">
                <div className="flex items-center gap-4">
                    <div className="text-4xl">📝</div>
                    <div>
                        <p className="text-white font-semibold">Mid-Semester Examinations</p>
                        <p className="text-slate-400 text-sm">{sorted.length} exams · Starts {formatDate(sorted[0]?.date)}</p>
                    </div>
                    <div className="ml-auto text-right">
                        <p className="text-3xl font-bold text-purple-400">{getDaysUntil(sorted[0]?.date)}</p>
                        <p className="text-slate-400 text-xs">days to go</p>
                    </div>
                </div>
            </div>

            {/* Exam cards */}
            <div className="space-y-3 fade-in">
                {sorted.map((exam, i) => {
                    const days = getDaysUntil(exam.date);
                    const isPast = days < 0;
                    const isToday = days === 0;
                    return (
                        <div key={exam.id} className={`glass-card p-4 flex items-center gap-4 hover:border-white/20 transition-all ${isPast ? "opacity-50" : ""}`}>
                            {/* Date badge */}
                            <div className={`w-14 h-14 rounded-2xl flex flex-col items-center justify-center flex-shrink-0 text-white
                ${isToday ? "bg-gradient-to-br from-red-600 to-orange-600 shadow-lg shadow-red-500/30" :
                                    isPast ? "bg-slate-700" :
                                        days <= 3 ? "bg-gradient-to-br from-amber-600 to-orange-600" :
                                            "bg-gradient-to-br from-purple-700 to-indigo-700"}`}>
                                <span className="text-xs font-medium opacity-80 uppercase">
                                    {new Date(exam.date).toLocaleDateString("en-IN", { month: "short" })}
                                </span>
                                <span className="text-xl font-bold leading-none">
                                    {new Date(exam.date).getDate()}
                                </span>
                            </div>

                            <div className="flex-1">
                                <div className="flex items-center gap-2 mb-1">
                                    <span className="text-white font-semibold">{exam.subject}</span>
                                    {isToday && <span className="text-xs bg-red-600 text-white px-2 py-0.5 rounded-full">TODAY</span>}
                                    {isPast && <span className="text-xs bg-slate-700 text-slate-400 px-2 py-0.5 rounded-full">DONE</span>}
                                </div>
                                <div className="flex flex-wrap gap-x-4 gap-y-1 text-xs text-slate-400">
                                    <span className="flex items-center gap-1"><Clock className="w-3 h-3" />{formatTime(exam.time)}</span>
                                    <span className="flex items-center gap-1"><CalendarDays className="w-3 h-3" />{exam.duration}</span>
                                    <span className="flex items-center gap-1"><BookOpen className="w-3 h-3" />{exam.type}</span>
                                </div>
                            </div>

                            <div className="text-right flex-shrink-0">
                                {!isPast && (
                                    <>
                                        <p className={`text-2xl font-bold ${days <= 3 ? "text-red-400" : days <= 7 ? "text-amber-400" : "text-purple-400"}`}>{days}</p>
                                        <p className="text-slate-500 text-xs">days left</p>
                                    </>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Important instructions */}
            <div className="glass-card p-5 mt-6 fade-in border-amber-500/20 bg-amber-500/5">
                <h3 className="text-amber-400 font-semibold mb-3 flex items-center gap-2">⚠️ Exam Instructions</h3>
                <ul className="space-y-1.5 text-sm text-slate-400">
                    <li>• Report to the exam hall 15 minutes before start time</li>
                    <li>• Carry your Hall Ticket and College ID Card</li>
                    <li>• Mobile phones are strictly prohibited in the exam hall</li>
                    <li>• Refer to the Seating Plan section for your seat number</li>
                </ul>
            </div>
        </DashboardLayout>
    );
}

"use client";

import { useState, useEffect } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_NOTICES } from "@/lib/demo-data";
import { formatDate } from "@/lib/utils";
import { db } from "@/lib/firebase";
import { collection, onSnapshot, query, orderBy } from "firebase/firestore";
import { Bell, BookOpen, Calendar, Star, Sun, Info } from "lucide-react";

const TYPE_CONFIG: Record<string, { icon: React.ElementType; color: string; bg: string }> = {
    exam: { icon: BookOpen, color: "text-purple-400", bg: "bg-purple-600/15 border-purple-500/20" },
    assignment: { icon: Star, color: "text-blue-400", bg: "bg-blue-600/15 border-blue-500/20" },
    event: { icon: Calendar, color: "text-amber-400", bg: "bg-amber-600/15 border-amber-500/20" },
    holiday: { icon: Sun, color: "text-emerald-400", bg: "bg-emerald-600/15 border-emerald-500/20" },
    general: { icon: Info, color: "text-slate-400", bg: "bg-slate-700/30 border-slate-600/20" },
};

export default function NoticesPage() {
    const [notices, setNotices] = useState<typeof DEMO_NOTICES>(DEMO_NOTICES);
    const [expanded, setExpanded] = useState<string | null>(null);
    const [filter, setFilter] = useState("all");
    const filters = ["all", "exam", "assignment", "event", "holiday", "general"];

    useEffect(() => {
        try {
            const q = query(collection(db, "notices"), orderBy("date", "desc"));
            const unsubscribe = onSnapshot(q, (snapshot) => {
                const fetchedNotices = snapshot.docs.map(doc => ({
                    id: doc.id,
                    ...doc.data(),
                    date: doc.data().date?.toDate?.()?.toISOString() || new Date().toISOString()
                })) as typeof DEMO_NOTICES;
                if (fetchedNotices.length > 0) {
                    setNotices(fetchedNotices);
                } else {
                    setNotices(DEMO_NOTICES);
                }
            }, (error) => {
                console.warn("Firestore listener failed, using demo data fallback.", error);
                setTimeout(() => setNotices(DEMO_NOTICES), 0);
            });

            return () => unsubscribe();
        } catch (error) {
            console.warn("Firestore connection failed.");
            setTimeout(() => setNotices(DEMO_NOTICES), 0);
        }
    }, []);

    const filtered = filter === "all" ? notices : notices.filter(n => n.type === filter);

    return (
        <DashboardLayout role="student" title="Notices">
            <div className="page-header">Notice Board</div>
            <p className="page-subheader">{notices.length} announcements from college & faculty</p>

            {/* Filter chips */}
            <div className="flex gap-2 mb-5 overflow-x-auto pb-1 fade-in">
                {filters.map(f => (
                    <button
                        key={f}
                        onClick={() => setFilter(f)}
                        className={`flex-shrink-0 px-3 py-1.5 rounded-full text-xs font-medium capitalize transition-all duration-200 ${filter === f
                            ? "bg-blue-600 text-white"
                            : "bg-white/5 text-slate-400 hover:text-white hover:bg-white/10"
                            }`}
                    >
                        {f === "all" ? `All (${notices.length})` : f}
                    </button>
                ))}
            </div>

            {/* Notices */}
            <div className="space-y-3 fade-in">
                {filtered.map(notice => {
                    const config = TYPE_CONFIG[notice.type] || TYPE_CONFIG.general;
                    const isExpanded = expanded === notice.id;
                    return (
                        <div
                            key={notice.id}
                            className={`border rounded-2xl p-4 cursor-pointer transition-all duration-300 ${config.bg} hover:border-white/20`}
                            onClick={() => setExpanded(isExpanded ? null : notice.id)}
                        >
                            <div className="flex items-start gap-3">
                                <div className={`w-9 h-9 rounded-xl bg-white/10 flex items-center justify-center flex-shrink-0 ${config.color}`}>
                                    <config.icon className="w-4 h-4" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="text-white font-medium text-sm leading-snug">{notice.title}</p>
                                    <div className="flex items-center gap-2 mt-1 text-xs text-slate-500">
                                        <span>{notice.author}</span>
                                        <span>·</span>
                                        <span>{formatDate(notice.date)}</span>
                                        <span className={`ml-auto capitalize ${config.color} font-medium`}>{notice.type}</span>
                                    </div>
                                    {isExpanded && (
                                        <p className="text-slate-300 text-sm mt-3 leading-relaxed border-t border-white/10 pt-3">
                                            {notice.body}
                                        </p>
                                    )}
                                </div>
                            </div>
                        </div>
                    );
                })}
                {filtered.length === 0 && (
                    <div className="glass-card p-10 text-center">
                        <Bell className="w-8 h-8 text-slate-600 mx-auto mb-2" />
                        <p className="text-slate-500">No notices in this category</p>
                    </div>
                )}
            </div>
        </DashboardLayout>
    );
}

"use client";

import { useState, useEffect } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_RESULTS } from "@/lib/demo-data";
import { useAuth } from "@/lib/auth-context";
import { db } from "@/lib/firebase";
import { collection, query, where, onSnapshot } from "firebase/firestore";
import { RadarChart, Radar, PolarGrid, PolarAngleAxis, ResponsiveContainer, Tooltip } from "recharts";

const GRADE_COLOR: Record<string, string> = {
    "A+": "text-emerald-400", "A": "text-emerald-400", "A-": "text-green-400",
    "B+": "text-blue-400", "B": "text-blue-400", "B-": "text-blue-400",
    "C": "text-amber-400", "D": "text-orange-400", "F": "text-red-400",
};

type ResultRecord = {
    subject: string;
    internal: number;
    external: number;
    total: number;
    max: number;
    grade: string;
};

export default function ResultsPage() {
    const { userProfile } = useAuth();
    const [resultsData, setResultsData] = useState<ResultRecord[]>(DEMO_RESULTS as ResultRecord[]);

    useEffect(() => {
        if (!userProfile?.rollNumber) return;

        try {
            const q = query(
                collection(db, "results"),
                where("rollNumber", "==", userProfile.rollNumber)
            );

            const unsubscribe = onSnapshot(q, (snapshot) => {
                if (snapshot.empty) {
                    setResultsData(DEMO_RESULTS as ResultRecord[]);
                    return;
                }
                const fetched = snapshot.docs.map(doc => doc.data() as ResultRecord);
                // Simple deduplication logic: if multiple results exist for a subject, take the latest
                // In a perfect system, we'd query by term as well
                const latestBySubject: Record<string, ResultRecord> = {};
                fetched.forEach(f => {
                    latestBySubject[f.subject] = f;
                });

                setResultsData(Object.values(latestBySubject));
            }, (error) => {
                console.warn("Firestore listener failed, using demo fallback.", error);
                setTimeout(() => setResultsData(DEMO_RESULTS as ResultRecord[]), 0);
            });

            return () => unsubscribe();
        } catch (error) {
            console.warn("Firestore connection failed.");
            setTimeout(() => setResultsData(DEMO_RESULTS as ResultRecord[]), 0);
        }
    }, [userProfile?.rollNumber]);

    const totalMarks = resultsData.reduce((s, r) => s + r.total, 0);
    const maxMarks = resultsData.reduce((s, r) => s + r.max, 0);
    const percentage = maxMarks > 0 ? Math.round((totalMarks / maxMarks) * 100) : 0;
    const cgpa = (percentage / 10).toFixed(2);

    const radarData = resultsData.map(r => ({
        subject: r.subject.split(" ")[0],
        score: Math.round((r.total / r.max) * 100),
    }));

    return (
        <DashboardLayout role="student" title="Results">
            <div className="page-header">Results & Grades</div>
            <p className="page-subheader">4th Semester · Academic Year 2025–26</p>

            {/* Summary */}
            <div className="grid grid-cols-3 gap-3 mb-6 fade-in">
                <div className="glass-card p-4 text-center">
                    <p className="text-3xl font-bold text-blue-400">{percentage}%</p>
                    <p className="text-slate-400 text-xs mt-1">Percentage</p>
                </div>
                <div className="glass-card p-4 text-center">
                    <p className="text-3xl font-bold text-purple-400">{cgpa}</p>
                    <p className="text-slate-400 text-xs mt-1">CGPA</p>
                </div>
                <div className="glass-card p-4 text-center">
                    <p className="text-3xl font-bold text-emerald-400">{totalMarks}</p>
                    <p className="text-slate-400 text-xs mt-1">/ {maxMarks} marks</p>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 mb-6">
                {/* Radar chart */}
                <div className="glass-card p-5 fade-in">
                    <h3 className="text-white font-semibold mb-4">Performance Overview</h3>
                    <ResponsiveContainer width="100%" height={220}>
                        <RadarChart data={radarData}>
                            <PolarGrid stroke="rgba(255,255,255,0.1)" />
                            <PolarAngleAxis dataKey="subject" tick={{ fill: "#94a3b8", fontSize: 10 }} />
                            <Radar dataKey="score" stroke="#6366f1" fill="#6366f1" fillOpacity={0.2} />
                            <Tooltip
                                contentStyle={{ background: "#1e293b", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 12 }}
                                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                formatter={(val: any) => [`${val}%`, "Score"]}
                            />
                        </RadarChart>
                    </ResponsiveContainer>
                </div>

                {/* Grade distribution */}
                <div className="glass-card p-5 fade-in">
                    <h3 className="text-white font-semibold mb-4">Grade Summary</h3>
                    <div className="space-y-3">
                        {resultsData.map((r, i) => (
                            <div key={i} className="flex items-center gap-3">
                                <span className="text-white text-xs font-medium w-28 flex-shrink-0 truncate">{r.subject.split(" ").slice(0, 2).join(" ")}</span>
                                <div className="flex-1 bg-white/5 rounded-full h-2">
                                    <div
                                        className="h-2 rounded-full bg-gradient-to-r from-blue-600 to-indigo-500"
                                        style={{ width: `${(r.total / r.max) * 100}%` }}
                                    />
                                </div>
                                <span className={`text-sm font-bold w-8 text-right ${GRADE_COLOR[r.grade] || "text-white"}`}>{r.grade}</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* Detailed marks */}
            <div className="glass-card overflow-hidden fade-in">
                <div className="p-5 border-b border-white/5">
                    <h3 className="text-white font-semibold">Detailed Marksheet</h3>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm">
                        <thead>
                            <tr className="border-b border-white/5">
                                <th className="text-left text-slate-400 text-xs font-medium px-5 py-3">Subject</th>
                                <th className="text-center text-slate-400 text-xs font-medium px-3 py-3">Internal (50)</th>
                                <th className="text-center text-slate-400 text-xs font-medium px-3 py-3">External (100)</th>
                                <th className="text-center text-slate-400 text-xs font-medium px-3 py-3">Total (150)</th>
                                <th className="text-center text-slate-400 text-xs font-medium px-3 py-3">Grade</th>
                            </tr>
                        </thead>
                        <tbody>
                            {resultsData.map((r, i) => (
                                <tr key={i} className="border-b border-white/3 hover:bg-white/3 transition-colors">
                                    <td className="text-white px-5 py-3 font-medium">{r.subject}</td>
                                    <td className="text-center text-slate-300 px-3 py-3">{r.internal}</td>
                                    <td className="text-center text-slate-300 px-3 py-3">{r.external}</td>
                                    <td className="text-center text-white font-semibold px-3 py-3">{r.total}</td>
                                    <td className="text-center px-3 py-3">
                                        <span className={`font-bold text-base ${GRADE_COLOR[r.grade] || "text-white"}`}>{r.grade}</span>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </DashboardLayout>
    );
}

"use client";

import { useEffect, useState } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { DEMO_TIMETABLE } from "@/lib/demo-data";
import { getCurrentDay, formatTime, cn } from "@/lib/utils";

export default function TodaySchedulePage() {
    const [now, setNow] = useState(new Date());
    const today = getCurrentDay();
    const classes = DEMO_TIMETABLE[today] || [];

    useEffect(() => {
        const interval = setInterval(() => setNow(new Date()), 1000);
        return () => clearInterval(interval);
    }, []);

    const getStatus = (startTime: string, endTime: string) => {
        const [sh, sm] = startTime.split(":").map(Number);
        const [eh, em] = endTime.split(":").map(Number);
        const nowMins = now.getHours() * 60 + now.getMinutes();
        const startMins = sh * 60 + sm;
        const endMins = eh * 60 + em;
        if (nowMins < startMins) return "upcoming";
        if (nowMins >= startMins && nowMins < endMins) return "ongoing";
        return "done";
    };

    const getCountdown = (startTime: string) => {
        const [h, m] = startTime.split(":").map(Number);
        const startMins = h * 60 + m;
        const nowMins = now.getHours() * 60 + now.getMinutes();
        const diff = startMins - nowMins;
        if (diff <= 0) return null;
        const hrs = Math.floor(diff / 60);
        const mins = diff % 60;
        return hrs > 0 ? `${hrs}h ${mins}m` : `${mins} min`;
    };

    const getTimeLeft = (endTime: string) => {
        const [h, m] = endTime.split(":").map(Number);
        const endMins = h * 60 + m;
        const nowMins = now.getHours() * 60 + now.getMinutes();
        const diff = endMins - nowMins;
        const hrs = Math.floor(diff / 60);
        const mins = diff % 60;
        return hrs > 0 ? `${hrs}h ${mins}m left` : `${mins} min left`;
    };

    return (
        <DashboardLayout role="student" title="Today's Schedule">
            <div className="page-header">Today's Schedule</div>
            <p className="page-subheader">{today} · {now.toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit", second: "2-digit" })}</p>

            {/* Live clock */}
            <div className="glass-card p-4 mb-6 flex items-center gap-4 fade-in">
                <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-blue-600 to-indigo-600 flex items-center justify-center flex-shrink-0">
                    <span className="text-white text-lg">🕐</span>
                </div>
                <div>
                    <p className="text-white text-2xl font-bold tabular-nums">
                        {now.toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" })}
                    </p>
                    <p className="text-slate-400 text-xs">{now.toLocaleDateString("en-IN", { weekday: "long", day: "numeric", month: "long" })}</p>
                </div>
                <div className="ml-auto text-right">
                    <p className="text-white font-semibold">{classes.length} Classes</p>
                    <p className="text-slate-400 text-xs">Scheduled today</p>
                </div>
            </div>

            {/* Timeline */}
            <div className="space-y-3 fade-in">
                {classes.length === 0 ? (
                    <div className="glass-card p-10 text-center">
                        <p className="text-4xl mb-3">🏖️</p>
                        <p className="text-white font-semibold">No classes today!</p>
                    </div>
                ) : (
                    classes.map((cls, i) => {
                        const status = getStatus(cls.time, cls.end);
                        const countdown = getCountdown(cls.time);
                        return (
                            <div
                                key={i}
                                className={cn(
                                    "border rounded-2xl p-4 transition-all duration-300 fade-in relative overflow-hidden",
                                    status === "ongoing"
                                        ? "bg-blue-600/15 border-blue-500/30"
                                        : status === "done"
                                            ? "bg-white/2 border-white/5 opacity-55"
                                            : "glass-card"
                                )}
                            >
                                {status === "ongoing" && (
                                    <div className="absolute top-0 left-0 right-0 h-0.5 bg-gradient-to-r from-blue-600 via-indigo-500 to-purple-600" />
                                )}
                                <div className="flex items-start gap-4">
                                    {/* Status indicator */}
                                    <div className="flex flex-col items-center gap-1 flex-shrink-0 mt-1">
                                        <div className={cn(
                                            "w-3 h-3 rounded-full",
                                            status === "ongoing" ? "bg-blue-400 pulse-glow" :
                                                status === "done" ? "bg-slate-600" : "bg-slate-700 border-2 border-slate-500"
                                        )} />
                                        {i < classes.length - 1 && <div className="w-0.5 h-8 bg-white/5" />}
                                    </div>

                                    {/* Content */}
                                    <div className="flex-1">
                                        <div className="flex items-start justify-between gap-2">
                                            <div>
                                                <div className="flex items-center gap-2 mb-0.5">
                                                    <span className="text-white font-semibold text-sm">{cls.subject}</span>
                                                    {status === "ongoing" && (
                                                        <span className="text-xs bg-blue-600 text-white px-2 py-0.5 rounded-full font-medium">LIVE</span>
                                                    )}
                                                </div>
                                                <p className="text-slate-500 text-xs">{cls.faculty}</p>
                                            </div>
                                            <div className="text-right flex-shrink-0">
                                                <p className="text-white text-xs font-medium">{formatTime(cls.time)}</p>
                                                <p className="text-slate-500 text-xs">{formatTime(cls.end)}</p>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-3 mt-2">
                                            <span className="text-xs text-slate-500">🏛️ Room {cls.room}</span>
                                            {status === "ongoing" && (
                                                <span className="text-xs text-blue-400 font-medium">{getTimeLeft(cls.end)}</span>
                                            )}
                                            {status === "upcoming" && countdown && (
                                                <span className="text-xs text-amber-400">Starts in {countdown}</span>
                                            )}
                                            {status === "done" && (
                                                <span className="text-xs text-slate-600">Completed ✓</span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>
        </DashboardLayout>
    );
}

