"use client";

import React, { createContext, useContext, useEffect, useState } from "react";
import { auth, db } from "./firebase";
import { signInWithEmailAndPassword, signOut, onAuthStateChanged } from "firebase/auth";
import { doc, getDoc } from "firebase/firestore";
import { DEMO_USERS } from "./demo-data";

export type UserRole = "student" | "faculty" | "coordinator" | null;

export interface UserProfile {
    id: string;
    name: string;
    email: string;
    role: UserRole;
    rollNumber?: string;
    semester?: string;
    branch?: string;
    division?: string;
    department?: string;
    phone?: string;
    photo?: string;
    subjects?: string[];
    classes?: string[];
}

interface AuthContextType {
    user: UserProfile | null;
    role: UserRole;
    loading: boolean;
    userProfile: UserProfile | null;
    login: (email: string, password: string) => Promise<void>;
    logout: () => Promise<void>;
    loadUserProfile: (uid?: string) => Promise<void>;
}

const AuthContext = createContext<AuthContextType>({
    user: null,
    role: null,
    loading: true,
    userProfile: null,
    login: async () => { },
    logout: async () => { },
    loadUserProfile: async () => { },
});

export function AuthProvider({ children }: { children: React.ReactNode }) {
    const [user, setUser] = useState<UserProfile | null>(null);
    const [role, setRole] = useState<UserRole>(null);
    const [loading, setLoading] = useState(true);

    const setSessionCookie = (role: UserRole) => {
        if (role) {
            document.cookie = `session_role=${role};path=/;max-age=86400`;
        } else {
            document.cookie = "session_role=;path=/;max-age=0";
        }
    };

    const handleMockLogin = (email: string, password: string): UserProfile => {
        const match = DEMO_USERS.find(
            u => u.email === email && u.password === password
        );
        if (!match) throw new Error("Invalid demo credentials");

        const profile: UserProfile = {
            id: match.uid,
            name: match.name,
            email: match.email,
            role: match.role as UserRole,
            ...(match.role === "student" ? {
                rollNumber: (match as any).rollNumber,
                semester: (match as any).semester,
                branch: (match as any).branch,
                division: (match as any).division,
                phone: match.phone,
            } : match.role === "faculty" ? {
                department: (match as any).department,
                subjects: (match as any).subjects,
                classes: (match as any).classes,
                phone: match.phone,
            } : {
                phone: match.phone,
            }),
        };
        return profile;
    };

    const loadUserProfile = async (uid?: string) => {
        const targetUid = uid || auth.currentUser?.uid;
        if (!targetUid) return;

        try {
            // Attempt to load from real Firestore if configured properly
            const docRef = doc(db, "users", targetUid);
            const docSnap = await getDoc(docRef);

            if (docSnap.exists()) {
                const profile = { id: targetUid, ...docSnap.data() } as UserProfile;
                setUser(profile);
                setRole(profile.role);
                setSessionCookie(profile.role);
                localStorage.setItem("edu_session", JSON.stringify(profile));
                return;
            }
        } catch (error) {
            console.warn("Firestore fetch failed, checking demo data fallback:", error);
        }

        // Fallback to DEMO matching if Firestore fails or document doesn't exist
        try {
            const profile = handleMockLogin(auth.currentUser?.email || "", "auto-fallback");
            setUser(profile);
            setRole(profile.role);
            setSessionCookie(profile.role);
            localStorage.setItem("edu_session", JSON.stringify(profile));
        } catch {
            console.warn("User has no firestore record and is not in DEMO data.");
        }
    };

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
            if (firebaseUser) {
                await loadUserProfile(firebaseUser.uid);
            } else {
                // If Firebase Auth is empty, check if we are purely in mock mode without API keys
                try {
                    const cached = localStorage.getItem("edu_session");
                    if (cached) {
                        const profile = JSON.parse(cached) as UserProfile;
                        setUser(profile);
                        setRole(profile.role);
                    } else {
                        setUser(null);
                        setRole(null);
                        setSessionCookie(null);
                    }
                } catch {
                    setUser(null);
                    setRole(null);
                }
            }
            setLoading(false);
        });

        return () => unsubscribe();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const login = async (email: string, password: string) => {
        try {
            // 1. Attempt Real Firebase Authentication
            const userCredential = await signInWithEmailAndPassword(auth, email, password);
            await loadUserProfile(userCredential.user.uid);
        } catch (error: unknown) {
            console.warn("Firebase Auth failed, attempting Mock Auth...", (error as Error).message);
            // 2. Fallback to Mock Auth if Firebase isn't correctly configured yet (demo keys)
            const profile = handleMockLogin(email, password);
            localStorage.setItem("edu_session", JSON.stringify(profile));
            setSessionCookie(profile.role);
            setUser(profile);
            setRole(profile.role);
        }
    };

    const logout = async () => {
        try {
            await signOut(auth);
        } catch (error) {
            console.warn("Firebase SignOut error:", error);
        }
        localStorage.removeItem("edu_session");
        setSessionCookie(null);
        setUser(null);
        setRole(null);
        window.location.href = "/login";
    };

    return (
        <AuthContext.Provider value={{ user, role, loading, userProfile: user, login, logout, loadUserProfile }}>
            {children}
        </AuthContext.Provider>
    );
}

export const useAuth = () => useContext(AuthContext);
